import { useState, useEffect } from "react";
import { T } from "../../assets/styles/theme";
import { Btn, Card, Badge, Avatar, Input } from "../../components/UI";
import { submitContactMessage, getOrganizations } from "../../api/auth";

// ─── NAVBAR ───────────────────────────────────────────────────────────────────
const NAV_LINKS = ["Home", "About", "Academics", "Achievements", "Members", "Gallery", "Contact"];

const PublicNav = ({ current, onNavigate, onGoToLogin }) => {
  const [menuOpen, setMenuOpen] = useState(false);

  return (
    <>
      <nav
        style={{
          position: "fixed",
          top: 0,
          left: 0,
          right: 0,
          zIndex: 1000,
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          padding: "0 20px",
          height: 66,
          background: "rgba(6,4,15,.92)",
          backdropFilter: "blur(20px)",
          borderBottom: `1px solid ${T.border}`,
        }}
      >
        {/* Logo */}
        <div
          style={{
            display: "flex",
            alignItems: "center",
            gap: 10,
            fontFamily: "Syne",
            fontSize: 18,
            fontWeight: 900,
          }}
        >
          <div
            style={{
              width: 34,
              height: 34,
              background: `linear-gradient(135deg, ${T.primary}, ${T.accent})`,
              borderRadius: 9,
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              fontSize: 16,
            }}
          >
            🎓
          </div>
          <span>
            Zenelait<span style={{ color: T.accent }}>InfoTech</span>
          </span>
        </div>

        {/* Desktop Menu */}
        <div
          className="desktop-menu"
          style={{
            display: "flex",
            alignItems: "center",
            gap: 26,
          }}
        >
          {NAV_LINKS.map((l) => (
            <button
              key={l}
              onClick={() => onNavigate(l.toLowerCase())}
              style={{
                background: "none",
                border: "none",
                cursor: "pointer",
                fontSize: 13,
                fontWeight: 500,
                color: current === l.toLowerCase() ? T.accent : T.white,
              }}
            >
              {l}
            </button>
          ))}
        </div>

        {/* Desktop Login Button */}
        <button
          className="desktop-login"
          onClick={onGoToLogin}
          style={{
            background: `linear-gradient(135deg, ${T.primary}, ${T.accent})`,
            border: "none",
            color: "#fff",
            padding: "10px 20px",
            borderRadius: 50,
            fontWeight: 800,
            fontSize: 13,
            cursor: "pointer",
            animation: "pulse 2s infinite",
          }}
        >
          🚀 Login
        </button>

        {/* Mobile Hamburger */}
        <div
          className="mobile-menu-icon"
          onClick={() => setMenuOpen(!menuOpen)}
          style={{
            display: "none",
            fontSize: 22,
            cursor: "pointer",
            color: "#fff",
          }}
        >
          ☰
        </div>
      </nav>

      {/* Mobile Dropdown */}
      {menuOpen && (
        <div
          style={{
            position: "fixed",
            top: 66,
            left: 0,
            right: 0,
            background: "rgba(10,10,20,0.98)",
            backdropFilter: "blur(20px)",
            padding: "20px",
            display: "flex",
            flexDirection: "column",
            gap: 16,
            zIndex: 999,
          }}
        >
          {NAV_LINKS.map((l) => (
            <button
              key={l}
              onClick={() => {
                onNavigate(l.toLowerCase());
                setMenuOpen(false);
              }}
              style={{
                background: "none",
                border: "none",
                textAlign: "left",
                fontSize: 15,
                color: current === l.toLowerCase() ? T.accent : "#fff",
                cursor: "pointer",
              }}
            >
              {l}
            </button>
          ))}

          <button
            onClick={() => {
              onGoToLogin();
              setMenuOpen(false);
            }}
            style={{
              marginTop: 10,
              background: `linear-gradient(135deg, ${T.primary}, ${T.accent})`,
              border: "none",
              color: "#fff",
              padding: "10px",
              borderRadius: 30,
              fontWeight: 700,
              cursor: "pointer",
            }}
          >
            🚀 Login / Register
          </button>
        </div>
      )}

      {/* Responsive CSS */}
      <style>
        {`
          @media (max-width: 768px) {
            .desktop-menu,
            .desktop-login {
              display: none !important;
            }

            .mobile-menu-icon {
              display: block !important;
            }
          }
        `}
      </style>
    </>
  );
};



// ─── FOOTER ───────────────────────────────────────────────────────────────────
const PublicFooter = () => {
  const [isMobile, setIsMobile] = useState(window.innerWidth < 768);

  useEffect(() => {
    const handler = () => setIsMobile(window.innerWidth < 768);
    window.addEventListener("resize", handler);
    return () => window.removeEventListener("resize", handler);
  }, []);

  return (
    <footer style={{ background: T.bg2, borderTop: `1px solid ${T.border}`, padding: isMobile ? "40px 24px 24px" : "50px 60px 28px", marginTop: 60 }}>
      <div style={{
        display: "grid",
        gridTemplateColumns: isMobile ? "1fr 1fr" : "2fr 1fr 1fr 1fr",
        gap: isMobile ? 28 : 36,
        maxWidth: 1100,
        margin: "0 auto"
      }}>
        {/* Brand block — full width on mobile */}
        <div style={{ gridColumn: isMobile ? "1 / -1" : "auto" }}>
          <div style={{ fontFamily: "Syne", fontSize: 18, fontWeight: 900, marginBottom: 12 }}>
            Zenelait<span style={{ color: T.accent }}>InfoTech</span>
          </div>
          <p style={{ fontSize: 13, color: T.muted, lineHeight: 1.7, maxWidth: 240 }}>
            Enterprise-grade Learning Management System for modern educational institutions.
          </p>
        </div>

        {[
          { h: "Platform", l: ["Students", "Teachers", "Parents", "Admin"] },
          { h: "Company", l: ["About Us", "Team", "Awards", "Blog"] },
          { h: "Legal", l: ["Privacy Policy", "Terms", "Cookies"] },
        ].map(col => (
          <div key={col.h}>
            <div style={{ fontSize: 11, fontWeight: 800, textTransform: "uppercase", letterSpacing: 1.2, color: T.muted, marginBottom: 14 }}>
              {col.h}
            </div>
            {col.l.map(l => (
              <div key={l}
                style={{ fontSize: 13, color: T.muted, marginBottom: 8, cursor: "pointer", transition: "color .2s" }}
                onMouseEnter={e => e.target.style.color = T.accent}
                onMouseLeave={e => e.target.style.color = T.muted}
              >{l}</div>
            ))}
          </div>
        ))}
      </div>

      <div style={{ textAlign: "center", fontSize: 12, color: T.muted, borderTop: `1px solid ${T.border}`, paddingTop: 24, marginTop: 36 }}>
        © 2025 Zenelait InfoTech. All rights reserved. Powered by Zenelait LMS v2.0
      </div>
    </footer>
  );
};

// ─── HOME PAGE ────────────────────────────────────────────────────────────────
// ─── HOME PAGE ────────────────────────────────────────────────────────────────
export const Home = ({ onLogin }) => (
  <div className="animated-fade-in">
    {/* HERO */}
    <section style={{ minHeight: "90vh", display: "flex", alignItems: "center", justifyContent: "center", position: "relative", overflow: "hidden", background: `radial-gradient(ellipse 80% 80% at 50% -10%, rgba(124,58,237,.28) 0%, transparent 70%), radial-gradient(ellipse 60% 60% at 80% 80%, rgba(6,182,212,.12) 0%, transparent 60%)` }}>
      {/* Floating abstract decorative objects */}
      <div className="lms-float-slow" style={{ position: "absolute", top: "12%", left: "10%", width: 140, height: 140, background: "rgba(124,58,237,0.12)", borderRadius: "50%", filter: "blur(40px)", pointerEvents: "none" }} />
      <div className="lms-float" style={{ position: "absolute", bottom: "15%", right: "12%", width: 180, height: 180, background: "rgba(6,182,212,0.08)", borderRadius: "50%", filter: "blur(50px)", pointerEvents: "none" }} />
      <div className="lms-float-slow" style={{ position: "absolute", top: "35%", right: "20%", width: 80, height: 80, background: "rgba(245,158,11,0.06)", borderRadius: "50%", filter: "blur(30px)", pointerEvents: "none" }} />

      <div style={{ textAlign: "center", maxWidth: 780, padding: "0 20px" }}>
        <div style={{ display: "inline-flex", alignItems: "center", gap: 8, background: "rgba(124,58,237,.15)", border: `1px solid rgba(124,58,237,.3)`, borderRadius: 50, padding: "6px 18px", fontSize: 12, fontWeight: 700, color: T.primaryL, marginBottom: 28 }}>
          <span style={{ width: 6, height: 6, borderRadius: "50%", background: T.accent, animation: "pulseDot 1.5s infinite", display: "inline-block" }} />
          Enterprise Learning Management System
        </div>
        <h1 style={{ fontFamily: "Syne", fontSize: "clamp(38px,6vw,72px)", fontWeight: 900, lineHeight: 1.08, marginBottom: 20, background: `linear-gradient(135deg, ${T.text}, ${T.primaryL} 50%, ${T.accent})`, WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent" }}>
          Transform Education<br />with Zenelait InfoTech
        </h1>
        <p style={{ fontSize: 17, color: T.muted, maxWidth: 520, margin: "0 auto 36px", lineHeight: 1.7, textAlign: "center" }}>
          A comprehensive AI-powered platform for students, teachers, parents & administrators.
        </p>
        <div style={{ display: "flex", gap: 16, justifyContent: "center", flexWrap: "wrap" }}>
          <Btn variant="primary" size="xl" onClick={onLogin} style={{ transform: "scale(1)", transition: "transform .2s" }} onMouseEnter={e => e.currentTarget.style.transform = "scale(1.05)"} onMouseLeave={e => e.currentTarget.style.transform = "scale(1)"}>Get Started →</Btn>
          <Btn variant="ghost" size="xl" style={{ transform: "scale(1)", transition: "transform .2s" }} onMouseEnter={e => e.currentTarget.style.transform = "scale(1.05)"} onMouseLeave={e => e.currentTarget.style.transform = "scale(1)"}>Watch Demo ▶</Btn>
        </div>
        <div style={{ display: "flex", gap: 48, justifyContent: "center", marginTop: 60, flexWrap: "wrap" }}>
          {[["12K+", "Active Students"], ["450+", "Courses"], ["98%", "Satisfaction"], ["85+", "Expert Teachers"]].map(([n, l]) => (
            <div key={l} style={{ textAlign: "center" }} className="lms-float">
              <div style={{ fontFamily: "Syne", fontSize: 36, fontWeight: 900, background: `linear-gradient(135deg, ${T.accent}, ${T.primaryL})`, WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent" }}>{n}</div>
              <div style={{ fontSize: 12, color: T.muted, marginTop: 2 }}>{l}</div>
            </div>
          ))}
        </div>
      </div>
    </section>

    {/* FEATURES */}
    <section style={{ padding: "80px 20px", maxWidth: 1200, margin: "0 auto" }}>
      <div style={{ textAlign: "center", marginBottom: 52 }}>
        <Badge type="primary">Platform Features</Badge>
        <h2 style={{ fontFamily: "Syne", fontSize: 38, fontWeight: 800, margin: "12px 0" }}>Everything You Need to Succeed</h2>
      </div>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(270px, 1fr))", gap: 22 }}>
        {[
          { icon: "📚", title: "Smart Course Management", desc: "Upload lectures, notes, assignments and videos with real-time progress tracking.", color: T.primaryL },
          { icon: "📊", title: "Real-Time Analytics", desc: "Comprehensive dashboards for all user roles with downloadable PDF reports.", color: T.accent },
          { icon: "🎯", title: "Exam & Assessment", desc: "Schedule exams, grade assignments, and auto-generate performance reports.", color: T.accentR },
          { icon: "💬", title: "Direct Communication", desc: "Students, teachers and parents communicate through integrated messaging.", color: T.accentY },
          { icon: "🎥", title: "Live Classes", desc: "Schedule and conduct live sessions via Zoom/Meet with attendance tracking.", color: T.accent },
          { icon: "🏆", title: "Certifications", desc: "Issue, manage and track digital certificates for course completions.", color: T.accentG },
        ].map(f => (
          <Card key={f.title} className="interactive-card" style={{ padding: 26 }}>
            <div className="feature-icon-box" style={{ width: 52, height: 52, borderRadius: 13, background: `${f.color}18`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 26, marginBottom: 16 }}>{f.icon}</div>
            <h3 style={{ fontSize: 16, fontWeight: 800, fontFamily: "Syne", marginBottom: 8 }}>{f.title}</h3>
            <p style={{ fontSize: 13, color: T.muted, lineHeight: 1.6 }}>{f.desc}</p>
          </Card>
        ))}
      </div>
    </section>

    {/* STATS BANNER */}
    <div style={{ margin: "0 20px 80px" }} className="stats-banner-wrap">
      <div className="stats-banner" style={{ padding: "56px 20px" }}>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(160px, 1fr))", gap: 32, textAlign: "center", position: "relative", zIndex: 1 }}>
          {[["12,000+", "Students Enrolled"], ["450+", "Courses Available"], ["85+", "Expert Instructors"], ["98%", "Satisfaction Rate"], ["5,000+", "Certifications Issued"]].map(([n, l]) => (
            <div key={l} className="lms-float">
              <div style={{ fontFamily: "Syne", fontSize: 30, fontWeight: 900, background: "linear-gradient(135deg,#fff,#06B6D4)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent" }}>{n}</div>
              <div style={{ fontSize: 13, color: "rgba(255,255,255,.65)", marginTop: 4 }}>{l}</div>
            </div>
          ))}
        </div>
      </div>
    </div>
  </div>
);

// ─── ABOUT PAGE ───────────────────────────────────────────────────────────────
export const About = () => (
  <div className="about-page animated-fade-in">
    <div style={{ textAlign: "center", marginBottom: 48 }}>
      <Badge type="primary">About Us</Badge>
      <h2 className="about-heading">About Zenelait InfoTech</h2>
      <p style={{ fontSize: 15, color: T.muted, marginTop: 8 }}>Pioneering digital education since 2018</p>
    </div>

    <div className="about-grid">
      {/* Mission Card */}
      <Card className="interactive-card" style={{ padding: 0, overflow: "hidden" }}>
        <div style={{ background: `linear-gradient(135deg, ${T.primary}18, ${T.accentG}10)`, padding: "22px 26px 16px", borderBottom: `1px solid ${T.border}` }}>
          <div className="lms-float" style={{ fontSize: 36, marginBottom: 8 }}>🎯</div>
          <h3 style={{ fontFamily: "Syne", fontSize: 20, fontWeight: 800, margin: 0 }}>Our Mission</h3>
        </div>
        <div style={{ padding: "24px 26px" }}>
          <p style={{ fontSize: 14, color: T.muted, lineHeight: 1.85, marginBottom: 20, textAlign: "justify" }}>
            Zenelait InfoTech Academy is dedicated to delivering world-class education through technology.
            We believe every student deserves access to quality learning regardless of geography or background.
          </p>
          {["Accredited online programs", "Industry-aligned curriculum", "Placement assistance program", "24/7 learning support"].map(item => (
            <div key={item} style={{ display: "flex", gap: 10, alignItems: "flex-start", marginBottom: 12 }}>
              <span style={{
                width: 22, height: 22, borderRadius: 6, flexShrink: 0,
                background: `${T.accentG}18`, border: `1px solid ${T.accentG}30`,
                display: "flex", alignItems: "center", justifyContent: "center",
                color: T.accentG, fontSize: 12, marginTop: 1
              }}>✓</span>
              <span style={{ fontSize: 13, color: T.text, lineHeight: 1.5 }}>{item}</span>
            </div>
          ))}
        </div>
      </Card>

      {/* Vision Card */}
      <Card className="interactive-card" style={{ padding: 0, overflow: "hidden" }}>
        <div style={{ background: `linear-gradient(135deg, ${T.accent}18, ${T.primary}10)`, padding: "22px 26px 16px", borderBottom: `1px solid ${T.border}` }}>
          <div className="lms-float" style={{ fontSize: 36, marginBottom: 8 }}>🌟</div>
          <h3 style={{ fontFamily: "Syne", fontSize: 20, fontWeight: 800, margin: 0 }}>Our Vision</h3>
        </div>
        <div style={{ padding: "24px 26px" }}>
          <p style={{ fontSize: 14, color: T.muted, lineHeight: 1.85, marginBottom: 22, textAlign: "justify" }}>
            To become India's most trusted EdTech platform, connecting learners and educators through
            cutting-edge technology and compassionate, outcome-driven education.
          </p>
          <div className="about-stats-grid">
            {[["2018", "Founded"], ["15+", "Departments"], ["200+", "Staff Members"], ["50+", "Awards Won"]].map(([v, l]) => (
              <div key={l} className="lms-float" style={{
                background: T.bg3, borderRadius: 12, padding: "16px 10px",
                textAlign: "center", border: `1px solid ${T.border}`
              }}>
                <div style={{ fontFamily: "Syne", fontSize: 28, fontWeight: 900, color: T.accent, lineHeight: 1.1 }}>{v}</div>
                <div style={{ fontSize: 11, color: T.muted, marginTop: 5, fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.5px" }}>{l}</div>
              </div>
            ))}
          </div>
        </div>
      </Card>
    </div>

    {/* Responsive styles */}
    <style>{`
      .about-page {
        padding: 60px 20px 80px;
        max-width: 1200px;
        margin: 0 auto;
      }
      .about-heading {
        font-family: Syne;
        font-size: 40px;
        font-weight: 800;
        margin: 12px 0 0;
      }
      .about-grid {
        display: grid;
        grid-template-columns: 1fr 1fr;
        gap: 24px;
      }
      .about-stats-grid {
        display: grid;
        grid-template-columns: 1fr 1fr;
        gap: 12px;
      }
      @media (max-width: 768px) {
        .about-page {
          padding: 32px 18px 60px;
        }
        .about-heading {
          font-size: 28px !important;
        }
        .about-grid {
          grid-template-columns: 1fr !important;
          gap: 18px;
        }
        .about-stats-grid {
          grid-template-columns: 1fr 1fr !important;
          gap: 10px;
        }
      }
      @media (max-width: 400px) {
        .about-stats-grid {
          grid-template-columns: 1fr 1fr !important;
        }
      }
    `}</style>
  </div>
);

// ─── ACADEMICS PAGE ───────────────────────────────────────────────────────────
export const Academics = () => (
  <div style={{ padding: "60px 60px 80px", maxWidth: 1200, margin: "0 auto" }}>
    <div style={{ textAlign: "center", marginBottom: 52 }}>
      <Badge type="primary">Academics</Badge>
      <h2 style={{ fontFamily: "Syne", fontSize: 38, fontWeight: 800, margin: "12px 0" }}>Our Course Programs</h2>
      <p style={{ fontSize: 15, color: T.muted }}>Explore 450+ courses across 15+ departments</p>
    </div>
    <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(290px, 1fr))", gap: 22 }}>
      {[
        { icon: "💻", title: "Full Stack Web Development", hrs: 120, enrolled: 1240, price: "₹12,000", badge: "info" },
        { icon: "📊", title: "Data Science & Machine Learning", hrs: 160, enrolled: 980, price: "₹15,000", badge: "success" },
        { icon: "📱", title: "Mobile App Development", hrs: 100, enrolled: 760, price: "₹10,000", badge: "primary" },
        { icon: "🔐", title: "Cyber Security Fundamentals", hrs: 90, enrolled: 620, price: "₹11,000", badge: "danger" },
        { icon: "🎨", title: "UI/UX Design Masterclass", hrs: 80, enrolled: 540, price: "₹8,000", badge: "warning" },
        { icon: "☁️", title: "Cloud Computing & DevOps", hrs: 140, enrolled: 890, price: "₹13,000", badge: "info" },
      ].map(c => (
        <Card key={c.title} style={{ overflow: "hidden", padding: 0 }}>
          <div style={{ height: 120, background: `linear-gradient(135deg, ${T.bg3}, ${T.card2})`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 52 }}>{c.icon}</div>
          <div style={{ padding: 18 }}>
            <h4 style={{ fontWeight: 800, fontSize: 15, fontFamily: "Syne", marginBottom: 8 }}>{c.title}</h4>
            <div style={{ display: "flex", gap: 14, fontSize: 12, color: T.muted, marginBottom: 12 }}>
              <span>⏱ {c.hrs} hrs</span><span>👥 {c.enrolled.toLocaleString()} enrolled</span>
            </div>
