// ─── CONTACT PAGE ─────────────────────────────────────────────────────────────
// Contact form data is stored in DB and shown in Admin → Contact Queries page
export const Contact = () => {
  const [orgs, setOrgs] = useState([]);
  const [sent, setSent] = useState(false);
  const [loading, setLoading] = useState(false);
  const [errors, setErrors] = useState({});
  const [form, setForm] = useState({
    name: "",
    email: "",
    phone: "",
    subject: "",
    message: "",
    organizationId: "",
  });

  useEffect(() => {
    getOrganizations()
      .then((data) => {
        // filter or list all active organizations
        setOrgs(Array.isArray(data) ? data : []);
      })
      .catch((err) => console.error("Failed to load organizations:", err));
  }, []);

  const f = (k) => (e) => setForm((p) => ({ ...p, [k]: e.target.value }));

  const validate = () => {
    const e = {};
    if (!form.organizationId) e.organizationId = "Organization is required";
    if (!form.name.trim()) e.name = "Name is required";
    if (!form.email.trim()) e.email = "Email is required";
    else if (!form.email.includes("@")) e.email = "Enter a valid email address";
    if (!form.phone.trim()) e.phone = "Phone number is required";
    else if (form.phone.replace(/\D/g, "").length < 10)
      e.phone = "Enter a valid phone number";

    setErrors(e);
    return Object.keys(e).length === 0;
  };

  const handleSend = async () => {
    if (!validate()) return;
    try {
      setLoading(true);
      await submitContactMessage(form);
      setSent(true);
    } catch (err) {
      alert("Failed to send message: " + err.message);
    } finally {
      setLoading(false);
    }
  };

  const inputStyle = (field) => ({
    width: "100%",
    background: T.bg3,
    border: `1.5px solid ${errors[field] ? "#ef4444" : T.border}`,
    borderRadius: 9,
    padding: "10px 14px",
    fontSize: 13,
    color: T.text,
    outline: "none",
    fontFamily: "DM Sans",
    boxSizing: "border-box",
  });

  const errTxt = (field) =>
    errors[field] ? (
      <div style={{ fontSize: 11, color: "#ef4444", marginTop: 4 }}>
        ⚠ {errors[field]}
      </div>
    ) : null;

  return (
    <div className="contact-container">
      {/* Header */}
      <div className="contact-header">
        <Badge type="info">Contact</Badge>
        <h2>Get In Touch</h2>
        <p>
          We're here to help. Messages are stored and reviewed by our admin team.
        </p>
      </div>

      {/* Content */}
      <div className="contact-grid">
        {/* Left Info */}
        <div>
          {[
            {
              icon: "📍",
              label: "Address",
              val: "Zenelait InfoTech, Anna Salai, Chennai, Tamil Nadu - 600002",
            },
            { icon: "📞", label: "Phone", val: "+91 98765 43210" },
            { icon: "✉️", label: "Email", val: "info@zenelaitinfotech.com" },
            {
              icon: "🕐",
              label: "Office Hours",
              val: "Mon–Sat: 9:00 AM – 6:00 PM",
            },
          ].map((c) => (
            <div key={c.label} className="contact-info-item">
              <div className="contact-icon">{c.icon}</div>
              <div>
                <div className="contact-label">{c.label}</div>
                <div className="contact-value">{c.val}</div>
              </div>
            </div>
          ))}
        </div>

        {/* Form */}
        <Card className="contact-card">
          <h3>Send a Message</h3>

          {!sent ? (
            <>
              <div className="field">
                <label>Organization *</label>
                <select
                  value={form.organizationId}
                  onChange={f("organizationId")}
                  style={inputStyle("organizationId")}
                >
                  <option value="" style={{ background: T.bg3, color: T.text }}>-- Select Organization --</option>
                  {orgs.map((org) => (
                    <option key={org.id} value={org.id} style={{ background: T.bg3, color: T.text }}>
                      {org.name}
                    </option>
                  ))}
                </select>
                {errTxt("organizationId")}
              </div>

              <div className="field">
                <label>Your Name *</label>
                <input
                  value={form.name}
                  onChange={f("name")}
                  placeholder="Enter your full name"
                  style={inputStyle("name")}
                />
                {errTxt("name")}
              </div>

              <div className="field">
                <label>Email Address *</label>
                <input
                  type="email"
                  value={form.email}
                  onChange={f("email")}
                  placeholder="your@email.com"
                  style={inputStyle("email")}
                />
                {errTxt("email")}
              </div>

              <div className="field">
                <label>Phone Number *</label>
                <input
                  value={form.phone}
                  onChange={f("phone")}
                  placeholder="+91 98765 43210"
                  style={inputStyle("phone")}
                />
                {errTxt("phone")}
              </div>

              <div className="field">
                <label>Subject</label>
                <input
                  value={form.subject}
                  onChange={f("subject")}
                  placeholder="What is this regarding?"
                  style={inputStyle("subject")}
                />
              </div>

              <div className="field">
                <label>Message</label>
                <textarea
                  rows={4}
                  value={form.message}
                  onChange={f("message")}
                  placeholder="Write your message here..."
                  style={{ ...inputStyle("message"), resize: "vertical" }}
                />
              </div>

              <Btn full onClick={handleSend} disabled={loading}>
                {loading ? "Sending..." : "Send Message →"}
              </Btn>
            </>
          ) : (
            <div className="success-box">
              <div className="success-icon">✅</div>
              <h3>Message Sent!</h3>
              <p>
                Your query has been stored. Our admin team will respond within 24
                hours.
              </p>
              <Btn
                onClick={() => {
                  setSent(false);
                  setForm({
                    name: "",
                    email: "",
                    phone: "",
                    subject: "",
                    message: "",
                  });
                }}
              >
                Send Another
              </Btn>
            </div>
          )}
        </Card>
      </div>

      {/* Responsive CSS */}
      <style>{`
        .contact-container {
          padding: 60px;
          max-width: 1100px;
          margin: auto;
        }

        .contact-header {
          text-align: center;
          margin-bottom: 50px;
        }

        .contact-header h2 {
          font-size: 38px;
          font-family: Syne;
          font-weight: 800;
          margin: 12px 0;
        }

        .contact-header p {
          font-size: 15px;
          color: ${T.muted};
        }

        .contact-grid {
          display: grid;
          grid-template-columns: 1fr 1.4fr;
          gap: 36px;
        }

        .contact-info-item {
          display: flex;
          gap: 16px;
          margin-bottom: 24px;
        }

        .contact-icon {
          width: 44px;
          height: 44px;
          background: ${T.primary}18;
          border-radius: 10px;
          display: flex;
          align-items: center;
          justify-content: center;
        }

        .contact-label {
          font-weight: 700;
          font-size: 14px;
        }

        .contact-value {
          font-size: 13px;
          color: ${T.muted};
        }

        .contact-card {
          padding: 28px;
        }

        .field {
          margin-bottom: 14px;
        }

        .field label {
          font-size: 11px;
          font-weight: 700;
          text-transform: uppercase;
          display: block;
          margin-bottom: 6px;
          color: ${T.muted};
        }

        .success-box {
          text-align: center;
          padding: 30px 0;
        }

        /* 📱 Mobile */
        @media (max-width: 768px) {
          .contact-container {
            padding: 30px 16px;
          }

          .contact-grid {
            grid-template-columns: 1fr;
          }

          .contact-header h2 {
            font-size: 28px;
          }

          .contact-card {
            padding: 20px;
          }
        }
      `}</style>
    </div>
  );
};

